1	interface Step {
2	  op: "quote";
3	  items: unknown[];
4	}
5	
6	interface Scenario {
7	  customer: { yearsWithMHPCO: number };
8	  steps: Step[];
9	}
10	
11	interface QuoteResult {
12	  premium: number;
13	}
14	
15	interface ScenarioOutput {
16	  results: QuoteResult[];
17	}
18	
19	const PROCESSING_FEE = 5;
20	
21	const BASE_PREMIUMS: Record<string, number> = {
22	  sword: 100,
23	  amulet: 60,
24	};
25	
26	export function processScenario(scenario: Scenario): ScenarioOutput {
27	  const results = scenario.steps.map((step) => {
28	    let basePremium = 0;
29	    for (const item of step.items) {
30	      basePremium += BASE_PREMIUMS[(item as any).type] ?? 0;
31	    }
32	    const premium = basePremium + PROCESSING_FEE;
33	    return { premium };
34	  });
35	  return { results };
36	}
