15	      const scenario = {
16	        customer: { yearsWithMHPCO: 0 },
17	        steps: [
18	          {
19	            op: "quote" as const,
20	            items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
21	          },
22	        ],
23	      };
24	      const result = processScenario(scenario);
25	      expect(result.results[0]).toEqual({ premium: 105 });
26	    });
