28	      const scenario = {
29	        customer: { yearsWithMHPCO: 0 },
30	        steps: [
31	          {
32	            op: "quote" as const,
33	            items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
34	          },
35	        ],
36	      };
