39	    });
40	    it.todo("returns base premium + fee for a single staff (80 + 5 = 85 G)");
41	    it.todo("returns base premium + fee for a single potion (40 + 5 = 45 G)");
42	    it.todo("returns 25 G base premium per component (e.g. 2 runes → 50 + 5 = 55 G)");
