44	    it.todo("does not apply block for 4 alike components (4 runes → 100 + 5 = 105 G)");
45	    it.todo("applies separate blocks for different component types (3 runes + 3 moonstones → 120 + 5 = 125 G)");
46	    it.todo("does not apply block for mixed component types (2 runes + 1 moonstone → 75 + 5 = 80 G)");
47	    it.todo("sums base premiums for multiple main items (sword + amulet → 160 + 5 = 165 G)");
48	  });
49	
50	  describe("Quote — item-specific modifiers", () => {
51	    it.todo("adds 50% cursed surcharge to the cursed item's base premium only");
52	    it.todo("adds 30% high-enchantment surcharge for enchantment >= 5");
53	    it.todo("does not add high-enchantment surcharge for enchantment 4");
54	    it.todo("applies both cursed and high-enchantment surcharges to the same item");
55	    it.todo("applies cursed surcharge only to cursed item in a multi-item policy");
56	  });
57	
58	  describe("Quote — policy-wide modifiers", () => {
59	    it.todo("applies 10% first-insurance surcharge for a newcomer");
60	    it.todo("applies 20% loyalty discount for customer with >= 2 years");
61	    it.todo("applies 15% follow-up contract discount on second quote");
62	    it.todo("applies loyalty, first-insurance, and follow-up together for long-standing repeat customer");
63	  });
64	
65	  describe("Quote — rounding", () => {
66	    it.todo("rounds premium up (in MHPCO's favor) on the final result");
67	  });
68	
69	  describe("Quote — integration", () => {
70	    it.todo("newcomer with cursed sword yields 165 G");
71	    it.todo("long-standing customer second contract with cursed high-enchant sword yields 160 G");
72	  });
73	
74	  describe("Claim — standard reimbursement", () => {
75	    it.todo("reimburses damage minus 100 G deductible for a regular item");
76	    it.todo("reimburses component damage minus 100 G deductible");
77	    it.todo("applies deductible per damaged item in a multi-damage event");
78	  });
79	
80	  describe("Claim — enchantment and material clauses", () => {
81	    it.todo("reimburses 50% for enchantment >= 8, then deductible");
82	    it.todo("fully reimburses dragon material items, then deductible");
83	    it.todo("applies 50% when both dragon material and enchantment >= 8");
84	    it.todo("fully reimburses dragon material with enchantment < 8, then deductible");
85	  });
86	
87	  describe("Claim — cap", () => {
88	    it.todo("caps total payout at 2x insurance sum of the policy");
89	    it.todo("tracks remaining cap across multiple claims on same policy");
